from llama_stack_client import LlamaStack
from vex_sdk import verify

llama = LlamaStack()

response = llama.invoke('What are the benefits of ProductX-123?')

result = verify(
    response,
    policy='ecommerce-product-claims',
    context={
        'product_id': 'ProductX-123',
        'catalog': {'claims': ['supports immunity', 'vitamin C'], 'prohibited': ['cures disease']}
    }
)

if result.valid:
    print(result.response)
else:
    print('Blocked unsubstantiated claim:', result.issues)

import json
from llama_stack_client import ToolResponse

@llama_stack_tool
def get_product_price(sku: str):
    return {'sku': sku, 'price': 29.99, 'currency': 'USD'}

response = llama.invoke('Price for SKU-456?')
tool_resp = ToolResponse(response.tools[0])

result = verify(
    tool_resp.data,
    schema={
        'type': 'object',
        'properties': {
            'price': {'type': 'number', 'minimum': 0},
            'currency': {'const': 'USD'}
        },
        'required': ['price', 'currency']
    }
)

if not result.valid:
    raise ValueError('Pricing schema violation')
